import Foundation
import RSDatabase
import RSDatabaseObjC

@MainActor final class AccountSettingsDatabase {

	private struct AccountCredentials {
		let username: String?
		let endpointURL: String?
	}

	private let credentialsByAccountID: [String: AccountCredentials]

	init?(databasePath: String) {
		guard FileManager.default.fileExists(atPath: databasePath) else {
			return nil
		}

		guard let database = FMDatabase(path: databasePath), database.open() else {
			return nil
		}
		defer {
			database.close()
		}

		var credentials = [String: AccountCredentials]()

		if let resultSet = database.executeQuery("SELECT accountID, username, endpointURL FROM accountSettings;", withArgumentsIn: []) {
			while resultSet.next() {
				guard let accountID = resultSet.swiftString(forColumn: "accountID") else {
					continue
				}
				let username = resultSet.swiftString(forColumn: "username")
				let endpointURL = resultSet.swiftString(forColumn: "endpointURL")
				if username != nil || endpointURL != nil {
					credentials[accountID] = AccountCredentials(username: username, endpointURL: endpointURL)
				}
			}
			resultSet.close()
		}

		self.credentialsByAccountID = credentials
	}

	func username(for accountID: String) -> String? {
		credentialsByAccountID[accountID]?.username
	}

	func endpointURL(for accountID: String) -> String? {
		credentialsByAccountID[accountID]?.endpointURL
	}
}

import SwiftSyntax

@SwiftSyntaxRule
struct LegacyRandomRule: Rule {
    var configuration = SeverityConfiguration<Self>(.warning)

    static let description = RuleDescription(
        identifier: "legacy_random",
        name: "Legacy Random",
        description: "Prefer using `type.random(in:)` over legacy functions",
        kind: .idiomatic,
        nonTriggeringExamples: [
            Example("Int.random(in: 0..<10)"),
            Example("Double.random(in: 8.6...111.34)"),
            Example("Float.random(in: 0 ..< 1)"),
        ],
        triggeringExamples: [
            Example("↓arc4random()"),
            Example("↓arc4random_uniform(83)"),
            Example("↓drand48()"),
        ]
    )
}

private extension LegacyRandomRule {
    final class Visitor: ViolationsSyntaxVisitor<ConfigurationType> {
        private static let legacyRandomFunctions: Set<String> = [
            "arc4random",
            "arc4random_uniform",
            "drand48",
        ]

        override func visitPost(_ node: FunctionCallExprSyntax) {
            if let function = node.calledExpression.as(DeclReferenceExprSyntax.self)?.baseName.text,
               Self.legacyRandomFunctions.contains(function) {
                violations.append(node.positionAfterSkippingLeadingTrivia)
            }
        }
    }
}

import SwiftSyntax

@SwiftSyntaxRule(optIn: true)
struct EmptyStringRule: Rule {
    var configuration = SeverityConfiguration<Self>(.warning)

    static let description = RuleDescription(
        identifier: "empty_string",
        name: "Empty String",
        description: "Prefer checking `isEmpty` over comparing `string` to an empty string literal",
        kind: .performance,
        nonTriggeringExamples: [
            Example("myString.isEmpty"),
            Example("!myString.isEmpty"),
            Example("\"\"\"\nfoo==\n\"\"\""),
        ],
        triggeringExamples: [
            Example(#"myString↓ == """#),
            Example(#"myString↓ != """#),
            Example(#"myString↓=="""#),
            Example(##"myString↓ == #""#"##),
            Example(###"myString↓ == ##""##"###),
        ]
    )
}

private extension EmptyStringRule {
    final class Visitor: ViolationsSyntaxVisitor<ConfigurationType> {
        override func visitPost(_ node: StringLiteralExprSyntax) {
            guard
                // Empty string literal: `""`, `#""#`, etc.
                node.segments.onlyElement?.trimmedLength == .zero,
                let previousToken = node.previousToken(viewMode: .sourceAccurate),
                // On the rhs of an `==` or `!=` operator
                previousToken.tokenKind.isEqualityComparison,
                let secondPreviousToken = previousToken.previousToken(viewMode: .sourceAccurate)
            else {
                return
            }

            let violationPosition = secondPreviousToken.endPositionBeforeTrailingTrivia
            violations.append(violationPosition)
        }
    }
}

